import React, { useState } from "react";
import TopNavBar from "../components/TopNavBar";
import Header from "../components/Header";
import { FiPlus, FiUser, FiChevronLeft } from "react-icons/fi";

// For navigation. Use useNavigate in v6+, or withRouter in v5
import { useNavigate } from "react-router-dom";

// Simple purple for selected tab
const TAB_BG_SEL = "#5D5FEF";
const TAB_BG = "#EDEDF9";

const avatarFallback = "https://randomuser.me/api/portraits/lego/2.jpg";

const emptyMyAccount = [
  // user account structure, always at least 1 row (me, customer)
  { name: "You", type: "Customer", phone: "", img: avatarFallback },
];

export default function Accounts() {
  const [tab, setTab] = useState("investors");
  const [investors, setInvestors] = useState([]); // start with empty
  const [myaccounts] = useState(emptyMyAccount);
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState({ name: "", phone: "", img: "" });

  const navigate = useNavigate();

  const addInvestor = () => {
    if (!form.name || !form.phone) return;
    setInvestors((prev) => [
      ...prev,
      { ...form, img: form.img || avatarFallback },
    ]);
    setForm({ name: "", phone: "", img: "" });
    setShowForm(false);
  };

  return (
    <div
      style={{ background: "#EAEDFB", minHeight: "100vh", paddingBottom: 80 }}
    >
      <Header />
      <TopNavBar />
      <div style={{ maxWidth: 440, margin: "30px auto", position: "relative" }}>
        {/* Back Button */}
        <button
          onClick={() => navigate(-1)}
          style={{
            position: "absolute",
            top: -22,
            left: -55,
            background: "none",
            border: "none",
            fontSize: 26,
            cursor: "pointer",
            color: "#273",
          }}
        >
          <FiChevronLeft />
        </button>
        {/* Card Panel */}
        <div
          style={{
            background: "#F3F6FC",
            borderRadius: 32,
            padding: 0,
            boxShadow: "0 2px 18px #b8bee345",
            minHeight: 420,
          }}
        >
          {/* Tabs */}
          <div
            style={{
              display: "flex",
              background: TAB_BG,
              borderRadius: "32px 32px 0 0",
            }}
          >
            <button
              onClick={() => setTab("investors")}
              style={{
                flex: 1,
                padding: "8px 0",
                background: tab === "investors" ? TAB_BG_SEL : "transparent",
                color: tab === "investors" ? "#fff" : "#5D5FEF",
                fontWeight: 600,
                fontSize: 16,
                border: "none",
                borderRadius: "32px 32px 0 0",
                cursor: "pointer",
              }}
            >
              Investors
            </button>
            <button
              onClick={() => setTab("myaccounts")}
              style={{
                flex: 1,
                padding: "8px 0",
                background: tab === "myaccounts" ? TAB_BG_SEL : "transparent",
                color: tab === "myaccounts" ? "#fff" : "#5D5FEF",
                fontWeight: 600,
                fontSize: 16,
                border: "none",
                borderRadius: "32px 32px 0 0",
                cursor: "pointer",
              }}
            >
              My Accounts
            </button>
          </div>
          <div style={{ padding: 18, paddingTop: 6 }}>
            <div
              style={{
                fontSize: 15,
                fontWeight: 600,
                color: "#434550",
                margin: "10px 0 16px",
              }}
            >
              Accounts
            </div>
            {/* List */}
            {tab === "investors" ? (
              <div>
                {investors.length === 0 && (
                  <div
                    style={{
                      fontStyle: "italic",
                      color: "#999",
                      textAlign: "center",
                      marginBottom: 12,
                    }}
                  >
                    No investors yet. Click below to add.
                  </div>
                )}
                {investors.map((inv, i) => (
                  <AccountCard key={i} {...inv} type="Investor" />
                ))}
                {/* Add New Investor */}
                {showForm ? (
                  <div
                    style={{
                      background: "#fff",
                      borderRadius: 16,
                      margin: "18px 0 10px 0",
                      padding: 16,
                    }}
                  >
                    <input
                      placeholder="Name"
                      value={form.name}
                      onChange={(e) =>
                        setForm((v) => ({ ...v, name: e.target.value }))
                      }
                      style={inputStyle}
                    />
                    <input
                      placeholder="Phone number"
                      value={form.phone}
                      onChange={(e) =>
                        setForm((v) => ({ ...v, phone: e.target.value }))
                      }
                      style={inputStyle}
                    />
                    <input
                      placeholder="Profile image URL (optional)"
                      value={form.img}
                      onChange={(e) =>
                        setForm((v) => ({ ...v, img: e.target.value }))
                      }
                      style={inputStyle}
                    />
                    <button style={submitBtn} onClick={addInvestor}>
                      Add
                    </button>
                    <button
                      onClick={() => setShowForm(false)}
                      style={{
                        ...submitBtn,
                        background: "#eee",
                        color: "#555",
                        marginTop: 4,
                      }}
                    >
                      Cancel
                    </button>
                  </div>
                ) : (
                  <button
                    style={{
                      width: "100%",
                      margin: "15px 0",
                      background: "#5D5FEF",
                      color: "#fff",
                      border: "none",
                      borderRadius: 20,
                      fontWeight: 700,
                      padding: "12px 0",
                      fontSize: 16,
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      gap: 9,
                    }}
                    onClick={() => setShowForm(true)}
                  >
                    <FiPlus size={19} /> New Investor
                  </button>
                )}
              </div>
            ) : (
              <div>
                {myaccounts.map((me, i) => (
                  <AccountCard key={i} {...me} more="Customer" />
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

function AccountCard({ name, type, phone, img, more }) {
  return (
    <div
      style={{
        background: "#fff",
        borderRadius: 16,
        padding: "10px 16px",
        display: "flex",
        alignItems: "center",
        marginBottom: 13,
        boxShadow: "0 2px 7px #cdd1f980",
      }}
    >
      <img
        src={img || avatarFallback}
        alt=""
        style={{
          width: 45,
          height: 45,
          borderRadius: "50%",
          objectFit: "cover",
          marginRight: 16,
        }}
      />
      <div style={{ flex: 1 }}>
        <div style={{ fontWeight: 600, fontSize: 15 }}>{name}</div>
        {type && <div style={{ color: "#21B956", fontSize: 13 }}>{type}</div>}
        <div style={{ color: "#9797a0", fontSize: 12 }}>{phone}</div>
      </div>
      <div
        style={{
          color: "#5D5FEF",
          fontWeight: 600,
          fontSize: 14,
          cursor: "pointer",
        }}
      >
        More
      </div>
    </div>
  );
}

const inputStyle = {
  padding: "8px 10px",
  margin: "8px 0",
  borderRadius: 8,
  border: "1px solid #dbdbf1",
  width: "100%",
  fontSize: 15,
};
const submitBtn = {
  width: "100%",
  background: "#5D5FEF",
  color: "#fff",
  border: "none",
  borderRadius: 18,
  padding: "9px 0",
  fontWeight: 700,
  fontSize: 15,
  marginTop: 7,
  cursor: "pointer",
};
